ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  start_date: vars.resolvedStartDate,
  end_date: vars.resolvedEndDate,
  total_workouts: vars.sql1Result[0].total_workouts,
  total_duration: vars.sql1Result[0].total_duration,
  duration_unit: vars.sql1Result[0].duration_unit,
  total_energy_burned: vars.sql1Result[0].total_energy_burned,
  by_activity_type: vars.sql2Result 
    groupBy ((row) -> row.activity_type)
    pluck ((rows, activityType) -> 
      do {
        var heartRate = rows filter ($.metric_type == "heart_rate")
        var activeEnergy = rows filter ($.metric_type == "active_energy")
        var basalEnergy = rows filter ($.metric_type == "basal_energy")
        var distance = rows filter ($.metric_type == "distance")
        var steps = rows filter ($.metric_type == "steps")
        var durationRow = vars.sql1Result filter ($.activity_type == activityType)
        ---
        {
          activity_type: activityType,
          count: rows[0].count,
          total_duration: durationRow[0].total_duration default null,
          (total_active_energy: activeEnergy[0].sum_value) if (sizeOf(activeEnergy) > 0),
          (total_basal_energy: basalEnergy[0].sum_value) if (sizeOf(basalEnergy) > 0),
          (total_energy_burned: (activeEnergy[0].sum_value default 0) + (basalEnergy[0].sum_value default 0)) if (sizeOf(activeEnergy) > 0 or sizeOf(basalEnergy) > 0),
          (total_distance: distance[0].sum_value) if (sizeOf(distance) > 0),
          (distance_unit: distance[0].unit) if (sizeOf(distance) > 0),
          (total_steps: steps[0].sum_value) if (sizeOf(steps) > 0),
          (avg_heart_rate: heartRate[0].avg_value) if (sizeOf(heartRate) > 0),
          (min_heart_rate: heartRate[0].min_value) if (sizeOf(heartRate) > 0),
          (max_heart_rate: heartRate[0].max_value) if (sizeOf(heartRate) > 0)
        }
      }
    )
}

%dw 2.0
output application/json
var total_duration = payload.stage_duration reduce ((item, accumulator) -> item + accumulator)
---
{
    start_date: vars.resolvedStartDate,
    end_date: vars.resolvedEndDate,
    total_duration_seconds:total_duration,
    stages: payload map ((item, index) ->{
        stage: item.stage,
        duration_seconds: item.stage_duration
    } )
}

%dw 2.0
output application/json

var point_metrics = "point_metrics": vars.pointMetricsResult map ((item) -> {
    metric_type: item.metric_type,
    start_date: vars.resolvedStartDate,
    end_date: vars.resolvedEndDate,
    average: item.average,
    min: item.min,
    max: item.max,
    count: item.count
})
var sleep_sessions = "sleep_sessions":{
    start_date: vars.resolvedStartDate,
    end_date: vars.resolvedEndDate,
    total_duration: vars.sleepSessionsResult.stage_duration reduce ((item, accumulator) -> item + accumulator),
    stages: vars.sleepSessionsResult map ((item, index) ->{
        stage: item.stage,
        stage_duration: item.stage_duration
    } ) }
var workouts = "workouts": {
  start_date: vars.resolvedStartDate,
  end_date: vars.resolvedEndDate,
  total_workouts: vars.workOutsResult1[0].total_workouts,
  total_duration: vars.workOutsResult1[0].total_duration,
  duration_unit: vars.workOutsResult1[0].duration_unit,
  total_energy_burned: vars.workOutsResult1[0].total_energy_burned,
  by_activity_type: vars.workOutsResult2
  groupBy ((row) -> row.activity_type)
  pluck ((rows, activityType) -> 
      do {
        var heartRate = rows filter ($.metric_type == "heart_rate")
        var activeEnergy = rows filter ($.metric_type == "active_energy")
        var basalEnergy = rows filter ($.metric_type == "basal_energy")
        var distance = rows filter ($.metric_type == "distance")
        var steps = rows filter ($.metric_type == "steps")
        var durationRow = vars.sql1Result filter ($.activity_type == activityType)
        ---
        {
          activity_type: activityType,
          count: rows[0].count,
          total_duration: durationRow[0].total_duration default null,
          (total_active_energy: activeEnergy[0].sum_value) if (sizeOf(activeEnergy) > 0),
          (total_basal_energy: basalEnergy[0].sum_value) if (sizeOf(basalEnergy) > 0),
          (total_energy_burned: (activeEnergy[0].sum_value default 0) + (basalEnergy[0].sum_value default 0)) if (sizeOf(activeEnergy) > 0 or sizeOf(basalEnergy) > 0),
          (total_distance: distance[0].sum_value) if (sizeOf(distance) > 0),
          (distance_unit: distance[0].unit) if (sizeOf(distance) > 0),
          (total_steps: steps[0].sum_value) if (sizeOf(steps) > 0),
          (avg_heart_rate: heartRate[0].avg_value) if (sizeOf(heartRate) > 0),
          (min_heart_rate: heartRate[0].min_value) if (sizeOf(heartRate) > 0),
          (max_heart_rate: heartRate[0].max_value) if (sizeOf(heartRate) > 0)
        }
      }
    )
}  

---
point_metrics ++ sleep_sessions ++ workouts
